mapper.select:
select a.id, a.order_no, a.currency_id, a.item_id, a.chain_tag, a.item_name, a.user_id, a.tg_user_id,
       a.channel_id, a.shareholder_id, a.lan_key, a.pay_merchant_id, a.pay_channel_id, a.pay_type_id,
       a.bind_data,  a.account, a.amount, a.fee, a.real_amount, a.real_law_amount, a.ratio,
       a.from_addr, a.order_status, a.remark, a.check_user_id, a.check_username, a.check_time, a.up_order_no,
       a.up_order_info, a.up_notify_info, a.withdraw_time, a.sign_time, a.sign, a.create_time,
b.channel_name as channelName, c.name as shareholderName, d.name as payMerchantName, e.name as payChannelName,
f.name as payTypeName, COALESCE(f.code, a.pay_code) as pay_code, g.user_tg_name as username,
utm.merchant_tag_codes as merchantTagCodes
from t_order_law_withdraw a
LEFT JOIN t_channel b ON a.channel_id = b.id
LEFT JOIN t_shareholder c ON a.shareholder_id = c.id
LEFT JOIN t_merchant_pay d ON a.pay_merchant_id = d.id
LEFT JOIN t_pay_channel e ON a.pay_channel_id = e.id
LEFT JOIN t_pay_type f ON a.pay_type_id = f.id
LEFT JOIN t_user g ON a.user_id = g.user_id
LEFT JOIN t_user_merchant_tag utm ON a.user_id = utm.user_id


    and a.order_no = #{orderNo}
    and a.currency_id = #{currencyId}
    and a.item_id = #{itemId}
    and a.chain_tag = #{chainTag}
    and a.item_name like concat('%', #{itemName}, '%')
    and a.user_id = #{userId}
    and a.tg_user_id = #{tgUserId}
    and a.channel_id = #{channelId}
    and a.shareholder_id = #{shareholderId}
    and a.lan_key = #{lanKey}
    and a.pay_merchant_id = #{payMerchantId}
    and a.pay_channel_id = #{payChannelId}
    and a.pay_type_id = #{payTypeId}
    and a.bind_data = #{bindData}
    and a.pay_code = #{payCode}
    and a.account = #{account}
    and a.amount = #{amount}
    and a.fee = #{fee}
    and a.real_amount = #{realAmount}
    and a.real_law_amount = #{realLawAmount}
    and a.ratio = #{ratio}
    and a.from_addr = #{fromAddr}
    and a.order_status = #{orderStatus}
    and a.check_user_id = #{checkUserId}
    and a.check_username like concat('%',
        #{checkUsername}, '%')


        and (


                a.check_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

    and a.up_order_no = #{upOrderNo}
    and a.up_order_info = #{upOrderInfo}
    and a.up_notify_info = #{upNotifyInfo}

        and (


                a.withdraw_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

    and a.sign_time = #{signTime}
    and a.sign = #{sign}

        and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

select
l.id, l.amount,l.user_id
from t_order_law_withdraw l


        and l.channel_id = #{channelId}


        and l.currency_id=#{id}


        and l.create_time BETWEEN #{startTime} AND #{endTime}

    and l.order_status=4

SELECT
COUNT(id) AS counts,
IFNULL(SUM(amount), 0) AS amount
FROM t_order_law_withdraw

    order_status = 4

        AND currency_id = #{id}


        AND withdraw_time BETWEEN #{startTime} AND #{endTime}


        AND channel_id = #{channelId}

select l.user_id from t_order_law_withdraw l


        and l.channel_id = #{channelId}


        and l.currency_id=#{currencyId}

    and l.order_status = 4

        AND l.create_time BETWEEN #{startTime} AND #{endTime}

select
count(id) as lawWithdrawNum,
IFNULL(SUM(amount), 0) as currencyLawWithdrawAmounts
from t_order_law_withdraw


        AND user_id = #{userId}


        AND order_status = #{orderStatus}


        AND currency_id = #{currencyId}


        AND withdraw_time BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) AS orderNum,
       IFNULL(SUM(a.amount), 0) AS amount,
       IFNULL(SUM(a.fee), 0) AS fee,
       IFNULL(SUM(a.real_amount), 0) AS realAmount,
       IFNULL(SUM(a.real_law_amount), 0) AS realLawAmount
FROM t_order_law_withdraw a

    and a.order_no = #{orderNo}
    and a.currency_id = #{currencyId}
    and a.item_id = #{itemId}
    and a.chain_tag = #{chainTag}
    and a.item_name like concat('%', #{itemName}, '%')
    and a.user_id = #{userId}
    and a.tg_user_id = #{tgUserId}
    and a.channel_id = #{channelId}
    and a.shareholder_id = #{shareholderId}
    and a.lan_key = #{lanKey}
    and a.pay_merchant_id = #{payMerchantId}
    and a.pay_channel_id = #{payChannelId}
    and a.pay_type_id = #{payTypeId}
    and a.bind_data = #{bindData}
    and a.pay_code = #{payCode}
    and a.account = #{account}
    and a.amount = #{amount}
    and a.fee = #{fee}
    and a.real_amount = #{realAmount}
    and a.real_law_amount = #{realLawAmount}
    and a.ratio = #{ratio}
    and a.from_addr = #{fromAddr}
    and a.order_status = #{orderStatus}
    and a.check_user_id = #{checkUserId}
    and a.check_username like concat('%',
        #{checkUsername}, '%')


        and (


                a.check_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

    and a.up_order_no = #{upOrderNo}
    and a.up_order_info = #{upOrderInfo}
    and a.up_notify_info = #{upNotifyInfo}

        and (


                a.withdraw_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )

    and a.sign_time = #{signTime}
    and a.sign = #{sign}

        and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )
